class Playground {
    async run(inputs) {
        const heights = inputs[0].split(',').map(Number);
        const n = heights.length;

        this.arr.init(heights);
        this.vars.init([['left', 0], ['right', n - 1], ['maxArea', 0]]);

        let left = 0;
        let right = n - 1;
        let maxArea = 0;

        while (left < right) {
            this.arr.highlight(left, '#00e0ff');
            this.arr.highlight(right, '#00e0ff');

            const h = Math.min(heights[left], heights[right]);
            const w = right - left;
            const area = h * w;

            this.log(`Calculating area between index ${left} and ${right}: min(h) * width = ${h} * ${w} = ${area}`);

            if (area > maxArea) {
                maxArea = area;
                this.vars.put('maxArea', maxArea);
            }

            this.vars.put('left', left);
            this.vars.put('right', right);

            await this.await();

            if (heights[left] < heights[right]) {
                this.arr.highlight(left, 'transparent');
                left++;
            } else {
                this.arr.highlight(right, 'transparent');
                right--;
            }
        }

        this.log(`Final Max Area: ${maxArea}`);
        return maxArea;
    }
}
